AdvancedScene = class("AdvancedScene", BaseScene)

function AdvancedScene:init()
    self.init = false
    local config = AdvancedSceneConfig:findById(self.Id)
    if config == nil then
        return
    end
    self.init = true
    self.initPos = config.InitPos
    self.monster = nil
    self.time = config.Time
    self.startTime = 0
    self.isStart = false
end

function AdvancedScene:isInit()
    return self.init
end

function AdvancedScene:onTick()
    if not self:isGameStart() then
        return
    end
    if os.time() - self.startTime > self.time then
        self:onGameEnd()
    end
end

function AdvancedScene:onPlayerJoin(player)
    player:teleportPos(self.initPos)
    AreaManager:checkPlayerPosition(player, self.initPos)
    player.advancingId = self.Id
    GamePacketSender:SendJoinAdvanced(player.rakssid)
    if self:isGameStart() then
        local time = self.time - (os.time() - self.startTime)
        GamePacketSender:SendStartAdvanced(player.rakssid, time, self.Id)
        if not self.monster then
            self:onBackHall(player)
        else
            self.monster:syncHpInfo(player)
        end
    end
end

function AdvancedScene:onPlayerQuit(player)
    player.advancingId = 0
    GamePacketSender:SendQuitAdvanced(player.rakssid)
end

function AdvancedScene:startAdvanced()
    if self:isGameStart() then
        return
    end
    self.startTime = os.time()
    self.isStart = true
    for _, player in pairs(self.Players) do
        GamePacketSender:SendStartAdvanced(player.rakssid, self.time, self.Id)
    end
    local config = AdvancedSceneConfig:findById(self.Id)
    if config == nil then
        self:onGameEnd()
        return
    end
    self.monster = GameMonster.new(config.MonsterId, config.MonsterPos, self)
end

function AdvancedScene:isGameStart()
    return self.isStart
end

function AdvancedScene:isGameRunning()
    return self.monster ~= nil
end

function AdvancedScene:onBackHall(player)
    player.curArea = Define.Area.CommonArea
    local pos = player:randomInitPos()
    player:teleportPos(pos)
    AreaManager:checkPlayerPosition(player, pos)
    player.advancingId = 0
    self:removePlayer(player)
end

---进阶结束
function AdvancedScene:onGameEnd()
    if not self:isGameRunning() then
        return
    end
    local isWin = false
    if self.monster ~= nil then
        if self.monster:isDead() then
            isWin = true
        else
            self.monster:onRemove(false)
        end
    end
    self.monster = nil
    for _, player in pairs(self.Players) do
        GamePacketSender:SendAdvancedResult(player.rakssid, isWin, self.Id)
    end
    LuaTimer:schedule(function()
        for _, player in pairs(self.Players) do
            player.curArea = Define.Area.CommonArea
            local pos = player:randomInitPos()
            player:teleportPos(pos)
            AreaManager:checkPlayerPosition(player, pos)
            if isWin then
                PlayerAdvancedSuccessEvent:invoke(player, self.Id)
            end
            self:onPlayerQuit(player)
        end
        self.Players = {}
        SceneManager:removeAdvancedScene(self)
    end, 5000)
end

return AdvancedScene